","isconfirm":"false","isSignatureConfig":true,"cellCode":"cell_1575439236876_6863","ecEnv":"product","regionType":"BUTTON","i18nKey":"WOM.buttonPropertyshowName.randon1575439276981.flag","name":"重启","operateType":"CUSTOM","onclick":"recoveryTaskEvent(event)","ONCLICK":"recoveryTaskEvent(event)","CODE":"makeTaskList_recoveryTask_add_WOM_1.0.0_produceTask_makeTaskList","NAME":"重启","ICONCLS":"cui-btn-add","USEINMORE":"false","SEPARATENUM":"0"},{"id":"stopTask","showname":"结束","namekey":"结束","buttonstyle":"add","operatetype":"CUSTOM","isHide":false,"ispermission":false,"isPublished":false,"buttonoperationcode":"makeTaskList_stopTask_add_WOM_1.0.0_produceTask_makeTaskList","funcname":"onclick=''stopTaskEvent(event)''","funcbody":"function stopTaskEvent(event) {\n    console.log(''%c stop'', ''color:red;'');\n    var selecteds = ReactAPI.getComponentAPI(\"SupDataGrid\").APIs(\"WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg\").getSelecteds();\n    if (selecteds.length == 0) {\n        ReactAPI.showMessage(\"w\", ReactAPI.international.getText(''SupDatagrid.button.error''));\n        return false;\n    }\n    var data = selecteds[0];\n    if (data.batchContral) {\n        //只有非批控的工单才可以操作\n        ReactAPI.showMessage(\"w\", ReactAPI.international.getText(''WOM.custom.randon1575958091725''));\n        return false;\n    }\n    if (data.status != 99) {\n        //请先将指令单生效再进行操作\n        ReactAPI.showMessage(\"w\", ReactAPI.international.getText(''WOM.custom.randon1575958171058''));\n        return false;\n    }\n    var taskRunState = data.taskRunState.id;\n    if (taskRunState != ''WOM_runState/runing'' && taskRunState != ''WOM_runState/paused'') {\n        //只有执行中或者已暂停的指令单可以结束\n        ReactAPI.showMessage(\"w\", ReactAPI.international.getText(''WOM.custom.randon1575958861853''));\n        return false;\n    }\n    var taskId = data.id;\n    var procReportId = '''';\n\n    $.ajax({\n        url: \"/msService/WOM/produceTask/produceTask/findProcReportIdByTaskId\",\n        type: ''get'',\n        async: false,\n        data: {\n            taskId: taskId\n        },\n        success: function (res) {\n            procReportId = res.result;\n        }\n    });\n    var url = url = \"/msService/WOM/procReport/procReport/outPutCommonTaskEdit?taskId.id=\" + taskId;\n    if (procReportId != '''') {\n        url += \"&id=\" + procReportId\n    }\n    // 对话框名称\n    const dialogName = ''outPutCommonDialog'';\n    // 打开工序编辑对话框\n    ReactAPI.createDialog(dialogName, {\n        title: ReactAPI.international.getText(''WOM.viewtitle.randon1575977285430''),  // 指令单完工报工\n        size: 6,\n        url: url,\n        isRef: false, // 是否开启参照\n        buttons: [{\n            text: ReactAPI.international.getText(''Button.text.save''),  // 保存\n            type: \"primary\",\n            onClick: event => {\n                let params = ReactAPI.getParamsInRequestUrl();\n                event.ReactAPI.submitFormData(''save'', function (res, message) {\n                    if (res.code == 200) {\n                        ReactAPI.destroyDialog(dialogName);\n                    }\n                })\n            }\n        }, {\n            text: ReactAPI.international.getText(''WOM.buttonPropertyshowName.randon1585560121170.flag''),  // 完成\n            type: \"primary\",\n            onClick: function (event) {\n                event.ReactAPI.submitFormData(''save'', function (res, message) {\n                    console.log(\"%c finish\", \"color:green;\");\n                    if (res.code == 200) {\n                        //生成报工单//结束指令单\n                        $.ajax({\n                            url: \"/msService/WOM/produceTask/produceTask/addOutputByOutPutDetails\",\n                            type: ''post'',\n                            async: false,\n                            data: {\n                                procReportId: procReportId,\n                                taskId: taskId\n                            },\n                            success: function (res) {\n                                if (res.code == 200) {\n                                    let data = res.data;\n                                    if (data.dealSuccessFlag) {\n                                        ReactAPI.destroyDialog(dialogName);\n                                        let currentPage = ReactAPI.getComponentAPI(\"SupDataGrid\").APIs(\"WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg\").getTablePagination().currentPage;\n                                        let pageSize = ReactAPI.getComponentAPI(\"SupDataGrid\").APIs(\"WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg\").getTablePagination().pageSize;\n                                        let url = \"/msService/WOM/produceTask/produceTask/makeTaskList-query\";\n                                        ReactAPI.getComponentAPI(\"SupDataGrid\")\n                                            .APIs(\"WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg\")\n                                            .refreshDataByRequst({\n                                                type: \"POST\",\n                                                url: url,\n                                                param: {\n                                                    classifyCodes: \",\",\n                                                    customCondition: {},\n                                                    pageNo: currentPage,\n                                                    paging: true,\n                                                    pageSize: pageSize,\n                                                },\n                                            }); //查询刷新PT；\n                                    } else {\n                                        ReactAPI.showMessage(\"f\", data.errorMessage);\n                                    }\n                                } else {\n                                    if(res.message === \"创建人ID不能为空!\"){\n                                        ReactAPI.showMessage(\"f\", ReactAPI.international.getText(''WOM.custom.random1633930723936''));\n                                    }else{\n                                        ReactAPI.showMessage(\"f\", res.message);\n                                    }\n                                    \n                                }\n                            },\n                            error: function (XMLHttpRequest, textStatus, errorThrown) {\n                                let errObj = JSON.parse(XMLHttpRequest.responseText);\n                                ReactAPI.showMessage(\"f\", errObj.message);\n                            }\n                        });\n                    }\n                })\n            }\n        }, {\n            text: ReactAPI.international.getText(''Button.text.close''),  // 关闭\n            onClick: event => {\n                ReactAPI.destroyDialog(dialogName);\n            }\n        }\n        ]\n    });\n}","funcbody_es5":"function stopTaskEvent(event) {\n    console.log(''%c stop'', ''color:red;'');\n    var selecteds = ReactAPI.getComponentAPI(\"SupDataGrid\").APIs(\"WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg\").getSelecteds();\n    if (selecteds.length == 0) {\n        ReactAPI.showMessage(\"w\", ReactAPI.international.getText(''SupDatagrid.button.error''));\n        return false;\n    }\n    var data = selecteds[0];\n    if (data.batchContral) {\n        //只有非批控的工单才可以操作\n        ReactAPI.showMessage(\"w\", ReactAPI.international.getText(''WOM.custom.randon1575958091725''));\n        return false;\n    }\n    if (data.status != 99) {\n        //请先将指令单生效再进行操作\n        ReactAPI.showMessage(\"w\", ReactAPI.international.getText(''WOM.custom.randon1575958171058''));\n        return false;\n    }\n    var taskRunState = data.taskRunState.id;\n    if (taskRunState != ''WOM_runState/runing'' && taskRunState != ''WOM_runState/paused'') {\n        //只有执行中或者已暂停的指令单可以结束\n        ReactAPI.showMessage(\"w\", ReactAPI.international.getText(''WOM.custom.randon1575958861853''));\n        return false;\n    }\n    var taskId = data.id;\n    var procReportId = '''';\n\n    $.ajax({\n        url: \"/msService/WOM/produceTask/produceTask/findProcReportIdByTaskId\",\n        type: ''get'',\n        async: false,\n        data: {\n            taskId: taskId\n        },\n        success: function success(res) {\n            procReportId = res.result;\n        }\n    });\n    var url = url = \"/msService/WOM/procReport/procReport/outPutCommonTaskEdit?taskId.id=\" + taskId;\n    if (procReportId != '''') {\n        url += \"&id=\" + procReportId;\n    }\n    // 对话框名称\n    var dialogName = ''outPutCommonDialog'';\n    // 打开工序编辑对话框\n    ReactAPI.createDialog(dialogName, {\n        title: ReactAPI.international.getText(''WOM.viewtitle.randon1575977285430''), // 指令单完工报工\n        size: 6,\n        url: url,\n        isRef: false, // 是否开启参照\n        buttons: [{\n            text: ReactAPI.international.getText(''Button.text.save''), // 保存\n            type: \"primary\",\n            onClick: function onClick(event) {\n                var params = ReactAPI.getParamsInRequestUrl();\n                event.ReactAPI.submitFormData(''save'', function (res, message) {\n                    if (res.code == 200) {\n                        ReactAPI.destroyDialog(dialogName);\n                    }\n                });\n            }\n        }, {\n            text: ReactAPI.international.getText(''WOM.buttonPropertyshowName.randon1585560121170.flag''), // 完成\n            type: \"primary\",\n            onClick: function onClick(event) {\n                event.ReactAPI.submitFormData(''save'', function (res, message) {\n                    console.log(\"%c finish\", \"color:green;\");\n                    if (res.code == 200) {\n                        //生成报工单//结束指令单\n                        $.ajax({\n                            url: \"/msService/WOM/produceTask/produceTask/addOutputByOutPutDetails\",\n                            type: ''post'',\n                            async: false,\n                            data: {\n                                procReportId: procReportId,\n                                taskId: taskId\n                            },\n                            success: function success(res) {\n                                if (res.code == 200) {\n                                    var _data = res.data;\n                                    if (_data.dealSuccessFlag) {\n                                        ReactAPI.destroyDialog(dialogName);\n                                        var currentPage = ReactAPI.getComponentAPI(\"SupDataGrid\").APIs(\"WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg\").getTablePagination().currentPage;\n                                        var pageSize = ReactAPI.getComponentAPI(\"SupDataGrid\").APIs(\"WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg\").getTablePagination().pageSize;\n                                        var _url = \"/msService/WOM/produceTask/produceTask/makeTaskList-query\";\n                                        ReactAPI.getComponentAPI(\"SupDataGrid\").APIs(\"WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg\").refreshDataByRequst({\n                                            type: \"POST\",\n                                            url: _url,\n                                            param: {\n                                                classifyCodes: \",\",\n                                                customCondition: {},\n                                                pageNo: currentPage,\n                                                paging: true,\n                                                pageSize: pageSize\n                                            }\n                                        }); //查询刷新PT；\n                                    } else {\n                                        ReactAPI.showMessage(\"f\", _data.errorMessage);\n                                    }\n                                } else {\n                                    if (res.message === \"创建人ID不能为空!\") {\n                                        ReactAPI.showMessage(\"f\", ReactAPI.international.getText(''WOM.custom.random1633930723936''));\n                                    } else {\n                                        ReactAPI.showMessage(\"f\", res.message);\n                                    }\n                                }\n                            },\n                            error: function error(XMLHttpRequest, textStatus, errorThrown) {\n                                var errObj = JSON.parse(XMLHttpRequest.responseText);\n                                ReactAPI.showMessage(\"f\", errObj.message);\n                            }\n                        });\n                    }\n                });\n            }\n        }, {\n            text: ReactAPI.international.getText(''Button.text.close''), // 关闭\n            onClick: function onClick(event) {\n                ReactAPI.destroyDialog(dialogName);\n            }\n        }]\n    });\n}","iscallback":"false","iscustomfunc":"false","useInMore":"false","isconfirm":"false","isSignatureConfig":true,"cellCode":"cell_1575439290308_7450","ecEnv":"product","regionType":"BUTTON","i18nKey":"WOM.buttonPropertyshowName.randon1575439301821.flag","name":"结束","operateType":"CUSTOM","onclick":"stopTaskEvent(event)","ONCLICK":"stopTaskEvent(event)","CODE":"makeTaskList_stopTask_add_WOM_1.0.0_produceTask_makeTaskList","NAME":"结束","ICONCLS":"cui-btn-add","USEINMORE":"false","SEPARATENUM":"0"},{"id":"earlyPutIn","showname":"提前放料","namekey":"提前放料","buttonstyle":"recover","operatetype":"CUSTOM","isHide":false,"ispermission":false,"isPublished":false,"buttonoperationcode":"makeTaskList_earlyPutIn_recover_WOM_1.0.0_produceTask_makeTaskList","funcname":"onclick=''earlyPutInFunc(event)''","funcbody":"function earlyPutInFunc(event) {\n    // 获取选中行\n    let selectedRows = ReactAPI.getComponentAPI(''SupDataGrid'').APIs(''WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg'').getSelecteds();\n    // 必须选中一行\n    if (!selectedRows.length) {\n        ReactAPI.showMessage(''w'', ReactAPI.international.getText(''foundation.common.selectNullData''));\n\n        return;\n    }\n    let selectedRow = selectedRows[0];\n    // 选中行单据是否执行中\n    if (selectedRow.taskRunState == null || selectedRow.taskRunState.id !== ''WOM_runState/runing'') {\n        ReactAPI.showMessage(''w'', ReactAPI.international.getText(''WOM.custom.randon1597044938864''));\n\n        return;\n    }\n    let advanceFlag = selectedRow.advanceCharge;\n    //是否勾选允许提前放料\n    if (advanceFlag == false) {\n        ReactAPI.showMessage(''w'', ReactAPI.international.getText(''WOM.custom.randon1591583966456''));\n\n    } else {\n        let orderId = selectedRow.id;\n\n        let feedCondition = selectedRow.feedCondition;\n        ReactAPI.openConfirm({\n            title: ReactAPI.international.getText(''WOM.custom.randon1597055078126''),\n            message: feedCondition,\n            buttons: [{\n                operatetype: \"yes\",\n                text: ReactAPI.international.getText(''WOM.custom.randon1596434273127''),\n                type: \"primary\",\n                onClick: function () {\n\n                    ReactAPI.request({\n                        type: \"get\",\n                        data: {},\n                        url: \"/msService/WOM/produceTask/produceTask/setAdvanceTrue/\" + orderId,\n\n                    }, function (res) {\n                        if (res.data.success) {\n                            ReactAPI.closeConfirm();\n                            let currentPage = ReactAPI.getComponentAPI(\"SupDataGrid\").APIs(\"WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg\").getTablePagination().currentPage;\n                            let pageSize = ReactAPI.getComponentAPI(\"SupDataGrid\").APIs(\"WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg\").getTablePagination().pageSize;\n                            let url = \"/msService/WOM/produceTask/produceTask/makeTaskList-query\";\n                            ReactAPI.getComponentAPI(\"SupDataGrid\")\n                                .APIs(\"WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg\")\n                                .refreshDataByRequst({\n                                    type: \"POST\",\n                                    url: url,\n                                    param: {\n                                        classifyCodes: \",\",\n                                        customCondition: {},\n                                        pageNo: currentPage,\n                                        paging: true,\n                                        pageSize: pageSize,\n                                    },\n                                });\n                            ReactAPI.showMessage(''s'', ReactAPI.international.getText(''WOM.custom.randon1591755924139''));\n                        }\n\n                    });\n\n                }\n            }, {\n                operatetype: \"no\",\n                text: ReactAPI.international.getText(''WOM.custom.randon1596434330969''),\n                type: \"primary\",\n                onClick: function () {\n                    ReactAPI.closeConfirm();\n                }\n            }\n            ]\n        });\n    }\n}","funcbody_es5":"function earlyPutInFunc(event) {\n    // 获取选中行\n    var selectedRows = ReactAPI.getComponentAPI(''SupDataGrid'').APIs(''WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg'').getSelecteds();\n    // 必须选中一行\n    if (!selectedRows.length) {\n        ReactAPI.showMessage(''w'', ReactAPI.international.getText(''foundation.common.selectNullData''));\n\n        return;\n    }\n    var selectedRow = selectedRows[0];\n    // 选中行单据是否执行中\n    if (selectedRow.taskRunState == null || selectedRow.taskRunState.id !== ''WOM_runState/runing'') {\n        ReactAPI.showMessage(''w'', ReactAPI.international.getText(''WOM.custom.randon1597044938864''));\n\n        return;\n    }\n    var advanceFlag = selectedRow.advanceCharge;\n    //是否勾选允许提前放料\n    if (advanceFlag == false) {\n        ReactAPI.showMessage(''w'', ReactAPI.international.getText(''WOM.custom.randon1591583966456''));\n    } else {\n        var orderId = selectedRow.id;\n\n        var feedCondition = selectedRow.feedCondition;\n        ReactAPI.openConfirm({\n            title: ReactAPI.international.getText(''WOM.custom.randon1597055078126''),\n            message: feedCondition,\n            buttons: [{\n                operatetype: \"yes\",\n                text: ReactAPI.international.getText(''WOM.custom.randon1596434273127''),\n                type: \"primary\",\n                onClick: function onClick() {\n\n                    ReactAPI.request({\n                        type: \"get\",\n                        data: {},\n                        url: \"/msService/WOM/produceTask/produceTask/setAdvanceTrue/\" + orderId\n\n                    }, function (res) {\n                        if (res.data.success) {\n                            ReactAPI.closeConfirm();\n                            var currentPage = ReactAPI.getComponentAPI(\"SupDataGrid\").APIs(\"WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg\").getTablePagination().currentPage;\n                            var pageSize = ReactAPI.getComponentAPI(\"SupDataGrid\").APIs(\"WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg\").getTablePagination().pageSize;\n                            var url = \"/msService/WOM/produceTask/produceTask/makeTaskList-query\";\n                            ReactAPI.getComponentAPI(\"SupDataGrid\").APIs(\"WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg\").refreshDataByRequst({\n                                type: \"POST\",\n                                url: url,\n                                param: {\n                                    classifyCodes: \",\",\n                                    customCondition: {},\n                                    pageNo: currentPage,\n                                    paging: true,\n                                    pageSize: pageSize\n                                }\n                            });\n                            ReactAPI.showMessage(''s'', ReactAPI.international.getText(''WOM.custom.randon1591755924139''));\n                        }\n                    });\n                }\n            }, {\n                operatetype: \"no\",\n                text: ReactAPI.international.getText(''WOM.custom.randon1596434330969''),\n                type: \"primary\",\n                onClick: function onClick() {\n                    ReactAPI.closeConfirm();\n                }\n            }]\n        });\n    }\n}","iscallback":"false","iscustomfunc":"false","useInMore":"false","isconfirm":"false","isSignatureConfig":true,"cellCode":"cell_1591581000619_8465","ecEnv":"product","regionType":"BUTTON","i18nKey":"WOM.buttonPropertyshowName.randon1591581142666.flag","name":"提前放料","operateType":"CUSTOM","onclick":"earlyPutInFunc(event)","ONCLICK":"earlyPutInFunc(event)","CODE":"makeTaskList_earlyPutIn_recover_WOM_1.0.0_produceTask_makeTaskList","NAME":"提前放料","ICONCLS":"cui-btn-recover","USEINMORE":"false","SEPARATENUM":"0"},{"id":"manuInspect","showname":"请检","namekey":"请检","buttonstyle":"add","operatetype":"CUSTOM","isHide":false,"ispermission":false,"isPublished":false,"buttonoperationcode":"makeTaskList_manuInspect_add_WOM_1.0.0_produceTask_makeTaskList","funcname":"onclick=''manuInspect(event)''","funcbody":"function manuInspect(event) {\n    // 获取选中行\n    let selectedRows = ReactAPI.getComponentAPI(''SupDataGrid'').APIs(''WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg'').getSelecteds();\n    // 必须选中一行\n    if (!selectedRows.length) {\n        ReactAPI.showMessage(''w'', ReactAPI.international.getText(''foundation.common.selectNullData''));\n        return;\n    }\n    let selectedRow = selectedRows[0];\n    // 选中行单据是否生效\n    if (selectedRow.status != 99) {\n        ReactAPI.showMessage(\"w\", ReactAPI.international.getText(''WOM.custom.randon1575958171058''));\n        return false;\n    }\n    //只有【执行中】的指令单允许请检！\n    if (selectedRow.taskRunState.id != \"WOM_runState/runing\") {\n        ReactAPI.showMessage(\"w\", ReactAPI.international.getText(''WOM.custom.randon1597996619261''));\n        return false;\n    }\n    //该指令单无需质检\n    if (selectedRow.inspectTimer == null) {\n        ReactAPI.showMessage(\"w\", ReactAPI.international.getText(''WOM.custom.randon1598676953828''));\n        return false;\n    }\n\n    var message = \"\";\n    var taskId = selectedRow.id;\n    //判断该批次的批次信息是否有待检或已检的检验报告\n    $.ajax({\n        url: \"/msService/WOM/produceTask/produceTask/findCheckMsgByBatch\",\n        type: ''get'',\n        async: false,\n        data: { taskId: taskId },\n        success: function (res) {\n            if (res.data.success) {\n                //检验状态\n                if (res.data.checkState != undefined) {\n                    if (res.data.checkState == \"待检\") {\n                        message = ReactAPI.international.getText(''WOM.custom.randon1598424040495'');\n                    } else {\n                        //该指令单检验状态为{} \n                        message = ReactAPI.international.getText(''WOM.custom.randon1597226087560'', res.data.checkState);\n                    }\n\n                }\n                // ,检验结论为{}\n                if (res.data.checkResult != undefined) {\n                    message += ReactAPI.international.getText(''WOM.custom.randon1597227115284'', res.data.checkResult);\n                }\n            }\n        }\n    });\n\n    if (message != '''') {\n        ReactAPI.openConfirm({\n            title: ReactAPI.international.getText(''WOM.custom.randon1597309436125''),\n            message: message,\n            buttons: [{\n                operatetype: \"yes\",\n                text: ReactAPI.international.getText(\"WOM.custom.randon1596434273127\"),// 是\n                type: \"primary\",\n                onClick: function () {\n                    ReactAPI.closeConfirm();\n                    //下推请检单\n                    $.ajax({\n                        url: \"/msService/WOM/produceTask/produceTask/createManuInspect\",\n                        type: ''post'',\n                        async: true,\n                        data: {\n                            \"taskId\": taskId\n                        },\n                        success: function (res) {\n                            if (res.code == 200) {\n                                let data = res.data;\n                                if (data.success) {\n                                    ReactAPI.showMessage(\"s\", ReactAPI.international.getText(\"WOM.custom.randon1597231220469\"));// 处理成功！\n                                    $(\"button[data-id = ''query'']\").click(); //查询刷新PT；\n                                } else {\n                                    ReactAPI.showMessage(\"f\", data.errMsg);\n                                }\n                            } else {\n                                ReactAPI.showMessage(\"f\", res.msg);\n                            }\n                        }\n                    });\n                }\n            }, {\n                operatetype: \"no\",\n                text: ReactAPI.international.getText(\"WOM.custom.randon1596434330969\"),// 否\n                type: \"primary\",\n                onClick: function () {\n                    ReactAPI.closeConfirm();\n                }\n            }\n            ]\n        });\n    } else {\n        ReactAPI.openConfirm({\n            title: ReactAPI.international.getText(''WOM.custom.randon1597309436125''),\n            buttons: [{\n                operatetype: \"yes\",\n                text: ReactAPI.international.getText(\"WOM.custom.randon1596434273127\"),// 是\n                type: \"primary\",\n                onClick: function () {\n                    ReactAPI.closeConfirm();\n                    //下推请检单\n                    $.ajax({\n                        url: \"/msService/WOM/produceTask/produceTask/createManuInspect\",\n                        type: ''post'',\n                        async: true,\n                        data: {\n                            \"taskId\": taskId\n                        },\n                        success: function (res) {\n                            if (res.code == 200) {\n                                let data = res.data;\n                                if (data.success) {\n                                    ReactAPI.showMessage(\"s\", ReactAPI.international.getText(\"WOM.custom.randon1597231220469\"));// 处理成功！\n                                    let currentPage = ReactAPI.getComponentAPI(\"SupDataGrid\").APIs(\"WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg\").getTablePagination().currentPage;\n                                    let pageSize = ReactAPI.getComponentAPI(\"SupDataGrid\").APIs(\"WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg\").getTablePagination().pageSize;\n                                    let url = \"/msService/WOM/produceTask/produceTask/makeTaskList-query\";\n                                    ReactAPI.getComponentAPI(\"SupDataGrid\")\n                                        .APIs(\"WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg\")\n                                        .refreshDataByRequst({\n                                            type: \"POST\",\n                                            url: url,\n                                            param: {\n                                                classifyCodes: \",\",\n                                                customCondition: {},\n                                                pageNo: currentPage,\n                                                paging: true,\n                                                pageSize: pageSize,\n                                            },\n                                        }); //查询刷新PT；\n                                } else {\n                                    ReactAPI.showMessage(\"f\", data.errMsg);\n                                }\n                            } else {\n                                ReactAPI.showMessage(\"f\", res.msg);\n                            }\n                        },\n                        error: function(res) {\n                            ReactAPI.showMessage(\"f\", res.responseJSON.message);\n                        }\n                    });\n                }\n            }, {\n                operatetype: \"no\",\n                text: ReactAPI.international.getText(\"WOM.custom.randon1596434330969\"),// 否\n                type: \"primary\",\n                onClick: function () {\n                    ReactAPI.closeConfirm();\n                }\n            }\n            ]\n        });\n    }\n}","funcbody_es5":"function manuInspect(event) {\n    // 获取选中行\n    var selectedRows = ReactAPI.getComponentAPI(''SupDataGrid'').APIs(''WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg'').getSelecteds();\n    // 必须选中一行\n    if (!selectedRows.length) {\n        ReactAPI.showMessage(''w'', ReactAPI.international.getText(''foundation.common.selectNullData''));\n        return;\n    }\n    var selectedRow = selectedRows[0];\n    // 选中行单据是否生效\n    if (selectedRow.status != 99) {\n        ReactAPI.showMessage(\"w\", ReactAPI.international.getText(''WOM.custom.randon1575958171058''));\n        return false;\n    }\n    //只有【执行中】的指令单允许请检！\n    if (selectedRow.taskRunState.id != \"WOM_runState/runing\") {\n        ReactAPI.showMessage(\"w\", ReactAPI.international.getText(''WOM.custom.randon1597996619261''));\n        return false;\n    }\n    //该指令单无需质检\n    if (selectedRow.inspectTimer == null) {\n        ReactAPI.showMessage(\"w\", ReactAPI.international.getText(''WOM.custom.randon1598676953828''));\n        return false;\n    }\n\n    var message = \"\";\n    var taskId = selectedRow.id;\n    //判断该批次的批次信息是否有待检或已检的检验报告\n    $.ajax({\n        url: \"/msService/WOM/produceTask/produceTask/findCheckMsgByBatch\",\n        type: ''get'',\n        async: false,\n        data: { taskId: taskId },\n        success: function success(res) {\n            if (res.data.success) {\n                //检验状态\n                if (res.data.checkState != undefined) {\n                    if (res.data.checkState == \"待检\") {\n                        message = ReactAPI.international.getText(''WOM.custom.randon1598424040495'');\n                    } else {\n                        //该指令单检验状态为{} \n                        message = ReactAPI.international.getText(''WOM.custom.randon1597226087560'', res.data.checkState);\n                    }\n                }\n                // ,检验结论为{}\n                if (res.data.checkResult != undefined) {\n                    message += ReactAPI.international.getText(''WOM.custom.randon1597227115284'', res.data.checkResult);\n                }\n            }\n        }\n    });\n\n    if (message != '''') {\n        ReactAPI.openConfirm({\n            title: ReactAPI.international.getText(''WOM.custom.randon1597309436125''),\n            message: message,\n            buttons: [{\n                operatetype: \"yes\",\n                text: ReactAPI.international.getText(\"WOM.custom.randon1596434273127\"), // 是\n                type: \"primary\",\n                onClick: function onClick() {\n                    ReactAPI.closeConfirm();\n                    //下推请检单\n                    $.ajax({\n                        url: \"/msService/WOM/produceTask/produceTask/createManuInspect\",\n                        type: ''post'',\n                        async: true,\n                        data: {\n                            \"taskId\": taskId\n                        },\n                        success: function success(res) {\n                            if (res.code == 200) {\n                                var data = res.data;\n                                if (data.success) {\n                                    ReactAPI.showMessage(\"s\", ReactAPI.international.getText(\"WOM.custom.randon1597231220469\")); // 处理成功！\n                                    $(\"button[data-id = ''query'']\").click(); //查询刷新PT；\n                                } else {\n                                    ReactAPI.showMessage(\"f\", data.errMsg);\n                                }\n                            } else {\n                                ReactAPI.showMessage(\"f\", res.msg);\n                            }\n                        }\n                    });\n                }\n            }, {\n                operatetype: \"no\",\n                text: ReactAPI.international.getText(\"WOM.custom.randon1596434330969\"), // 否\n                type: \"primary\",\n                onClick: function onClick() {\n                    ReactAPI.closeConfirm();\n                }\n            }]\n        });\n    } else {\n        ReactAPI.openConfirm({\n            title: ReactAPI.international.getText(''WOM.custom.randon1597309436125''),\n            buttons: [{\n                operatetype: \"yes\",\n                text: ReactAPI.international.getText(\"WOM.custom.randon1596434273127\"), // 是\n                type: \"primary\",\n                onClick: function onClick() {\n                    ReactAPI.closeConfirm();\n                    //下推请检单\n                    $.ajax({\n                        url: \"/msService/WOM/produceTask/produceTask/createManuInspect\",\n                        type: ''post'',\n                        async: true,\n                        data: {\n                            \"taskId\": taskId\n                        },\n                        success: function success(res) {\n                            if (res.code == 200) {\n                                var data = res.data;\n                                if (data.success) {\n                                    ReactAPI.showMessage(\"s\", ReactAPI.international.getText(\"WOM.custom.randon1597231220469\")); // 处理成功！\n                                    var currentPage = ReactAPI.getComponentAPI(\"SupDataGrid\").APIs(\"WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg\").getTablePagination().currentPage;\n                                    var pageSize = ReactAPI.getComponentAPI(\"SupDataGrid\").APIs(\"WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg\").getTablePagination().pageSize;\n                                    var url = \"/msService/WOM/produceTask/produceTask/makeTaskList-query\";\n                                    ReactAPI.getComponentAPI(\"SupDataGrid\").APIs(\"WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg\").refreshDataByRequst({\n                                        type: \"POST\",\n                                        url: url,\n                                        param: {\n                                            classifyCodes: \",\",\n                                            customCondition: {},\n                                            pageNo: currentPage,\n                                            paging: true,\n                                            pageSize: pageSize\n                                        }\n                                    }); //查询刷新PT；\n                                } else {\n                                    ReactAPI.showMessage(\"f\", data.errMsg);\n                                }\n                            } else {\n                                ReactAPI.showMessage(\"f\", res.msg);\n                            }\n                        },\n                        error: function error(res) {\n                            ReactAPI.showMessage(\"f\", res.responseJSON.message);\n                        }\n                    });\n                }\n            }, {\n                operatetype: \"no\",\n                text: ReactAPI.international.getText(\"WOM.custom.randon1596434330969\"), // 否\n                type: \"primary\",\n                onClick: function onClick() {\n                    ReactAPI.closeConfirm();\n                }\n            }]\n        });\n    }\n}","iscallback":"false","iscustomfunc":"false","useInMore":"false","isconfirm":"false","isSignatureConfig":true,"cellCode":"cell_1597201784444_672","ecEnv":"product","regionType":"BUTTON","i18nKey":"WOM.buttonPropertyshowName.randon1597201819098.flag","name":"请检","operateType":"CUSTOM","onclick":"manuInspect(event)","ONCLICK":"manuInspect(event)","CODE":"makeTaskList_manuInspect_add_WOM_1.0.0_produceTask_makeTaskList","NAME":"请检","ICONCLS":"cui-btn-add","USEINMORE":"false","SEPARATENUM":"0"},{"id":"prodprocessView","showname":"生产过程追溯","namekey":"生产过程追溯","buttonstyle":"add","operatetype":"CUSTOM","isHide":false,"ispermission":false,"isPublished":false,"buttonoperationcode":"makeTaskList_prodprocessView_add_WOM_1.0.0_produceTask_makeTaskList","funcname":"onclick=''prodprocessView(event)''","funcbody":"function prodprocessView(event){\n    let selected = ReactAPI.getComponentAPI().SupDataGrid.APIs(\"WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg\").getSelecteds();\n    if(selected.length<=0){\n        ReactAPI.showMessage(''w'', \"请先选择一条指令单!\");\n        return;\n\t}\n\tif(selected.length>1){\n\t\tReactAPI.showMessage(''w'', \"只可以进行单批次查看!\");\n\t\treturn;\n\t}\n    if(selected[0].taskRunState==null||selected[0].taskRunState.value==\"待执行\"){\n        ReactAPI.showMessage(''w'', \"未执行的指令单，请重新选择!\");\n        return;\n    }\n\tvar batchNo=selected[0].produceBatchNum;\n    var productNo = selected[0].productId.code;\n\t//调用接口，传批号，返回\n\t$.ajax({\n\t\ttype: \"GET\",\n\t\turl: \"/msService/ProcessAnalysis/analysisParam/analysisParam/isProdprocessView\",\n\t\tdata: { \"batchNo\": batchNo},\n\t\ttraditional: true,\n\t\tasync: false,\n\t\tsuccess: function(msg) {\n\t\t\tvar resdata = msg.data;\n\t\t\tif (msg.code == 200) {\n                var resflag = false;\n                for(var key in resdata){\n\t\t\t\t\tif(key==\"dealRes\"){//存在不符合要求的指令单\n\t\t\t\t\t    resflag=resdata[key];\n\t\t\t\t\t}\n                }\n                console.log(\"resflag=\"+resflag);\n\t\t\t\t\t//打开页面\n                if(resflag){\n                       //打开页面\n\t\t\t\t\t/*var powercode = ReactAPI.getPowerCode(\"ProcessAnalysis_1.0.0_processAnalysis_processBatchViewOut_self\", function(res) {\n\t\t\t\t\t\tconsole.log(res);\n                      }); \n                    var url=\"/msService/ProcessAnalysis/processAnalysis/exelogSecond/processBatchView?batchNo=\"+batchNo+\"&productNo=\"+productNo;\n\t\t\t\t    window.open(url);*/\n\t\t\t\t    var powercode = ReactAPI.getPowerCode(\"ProcessAnalysis_1.0.0_processAnalysis_processBatchViewOut_self\", function(res) {\n\t\t\t\t    \tconsole.log(res);\n\t\t\t\t   }); \n\t\t\t\t   var url=\"/msService/ProcessAnalysis/processAnalysis/exelogSecond/processBatchViewOut?__pc__=\"+Object.values(powercode)+\"&workFlowMenuCode=ProcessAnalysis_1.0.0_processAnalysis_processBatchViewOut&openType=page&batchNo=\"+batchNo+\"&productNo=\"+productNo;\n\t\t\t       window.open(url);\n                }\n                else{\n                    ReactAPI.showMessage(''w'', \"该批次不存在已统计的活动记录！\");\n                }\n\t\t\t\t\t\n\t\t\t} else {\n\t\t\t\tReactAPI.showMessage(''w'', \"内部错误\");\n\t\t\t}\n\t\t}\n\t});\n}","funcbody_es5":"function prodprocessView(event) {\n\tvar selected = ReactAPI.getComponentAPI().SupDataGrid.APIs(\"WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg\").getSelecteds();\n\tif (selected.length <= 0) {\n\t\tReactAPI.showMessage(''w'', \"请先选择一条指令单!\");\n\t\treturn;\n\t}\n\tif (selected.length > 1) {\n\t\tReactAPI.showMessage(''w'', \"只可以进行单批次查看!\");\n\t\treturn;\n\t}\n\tif (selected[0].taskRunState == null || selected[0].taskRunState.value == \"待执行\") {\n\t\tReactAPI.showMessage(''w'', \"未执行的指令单，请重新选择!\");\n\t\treturn;\n\t}\n\tvar batchNo = selected[0].produceBatchNum;\n\tvar productNo = selected[0].productId.code;\n\t//调用接口，传批号，返回\n\t$.ajax({\n\t\ttype: \"GET\",\n\t\turl: \"/msService/ProcessAnalysis/analysisParam/analysisParam/isProdprocessView\",\n\t\tdata: { \"batchNo\": batchNo },\n\t\ttraditional: true,\n\t\tasync: false,\n\t\tsuccess: function success(msg) {\n\t\t\tvar resdata = msg.data;\n\t\t\tif (msg.code == 200) {\n\t\t\t\tvar resflag = false;\n\t\t\t\tfor (var key in resdata) {\n\t\t\t\t\tif (key == \"dealRes\") {\n\t\t\t\t\t\t//存在不符合要求的指令单\n\t\t\t\t\t\tresflag = resdata[key];\n\t\t\t\t\t}\n\t\t\t\t}\n\t\t\t\tconsole.log(\"resflag=\" + resflag);\n\t\t\t\t//打开页面\n\t\t\t\tif (resflag) {\n\t\t\t\t\t//打开页面\n\t\t\t\t\t/*var powercode = ReactAPI.getPowerCode(\"ProcessAnalysis_1.0.0_processAnalysis_processBatchViewOut_self\", function(res) {\n     \tconsole.log(res);\n                      }); \n                    var url=\"/msService/ProcessAnalysis/processAnalysis/exelogSecond/processBatchView?batchNo=\"+batchNo+\"&productNo=\"+productNo;\n        window.open(url);*/\n\t\t\t\t\tvar powercode = ReactAPI.getPowerCode(\"ProcessAnalysis_1.0.0_processAnalysis_processBatchViewOut_self\", function (res) {\n\t\t\t\t\t\tconsole.log(res);\n\t\t\t\t\t});\n\t\t\t\t\tvar url = \"/msService/ProcessAnalysis/processAnalysis/exelogSecond/processBatchViewOut?__pc__=\" + Object.values(powercode) + \"&workFlowMenuCode=ProcessAnalysis_1.0.0_processAnalysis_processBatchViewOut&openType=page&batchNo=\" + batchNo + \"&productNo=\" + productNo;\n\t\t\t\t\twindow.open(url);\n\t\t\t\t} else {\n\t\t\t\t\tReactAPI.showMessage(''w'', \"该批次不存在已统计的活动记录！\");\n\t\t\t\t}\n\t\t\t} else {\n\t\t\t\tReactAPI.showMessage(''w'', \"内部错误\");\n\t\t\t}\n\t\t}\n\t});\n}","iscallback":"false","iscustomfunc":"false","useInMore":"false","isconfirm":"false","isSignatureConfig":true,"cellCode":"cell_1628652227072_1369","ecEnv":"product","regionType":"BUTTON","i18nKey":"WOM.buttonPropertyshowName.randon1628658336505.flag","name":"生产过程追溯","operateType":"CUSTOM","onclick":"prodprocessView(event)","ONCLICK":"prodprocessView(event)","CODE":"makeTaskList_prodprocessView_add_WOM_1.0.0_produceTask_makeTaskList","NAME":"生产过程追溯","ICONCLS":"cui-btn-add","USEINMORE":"false","SEPARATENUM":"0"},{"id":"generateCode","showname":"生成二维码","namekey":"生成二维码","buttonstyle":"add","operatetype":"CUSTOM","isHide":false,"ispermission":false,"isPublished":false,"buttonoperationcode":"makeTaskList_generateCode_add_WOM_1.0.0_produceTask_makeTaskList","funcname":"onclick=''customClick()''","funcbody":"function customClick() {\n    let seleData = ReactAPI.getComponentAPI(\"SupDataGrid\").APIs(''WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg'').getSelecteds();\n    if (seleData.length === 0) {\n        ReactAPI.showMessage(\"w\", ''请选择一条记录进行操作！'');\n        return false;\n    }\n    // let runState = seleData[0].taskRunState;\n    // if (!(runState !== null && (runState.id === ''WOM_runState/runing'' || runState.id === ''WOM_runState/finished''))) {\n    //     ReactAPI.showMessage(\"w\", ''只有执行中和已完成的工单可以生成二维码！'');\n    //     return false;\n    // }\n    // 二维码生成窗口\n    ReactAPI.createDialog(\"newDialog\", {\n        title: \"二维码生成\",\n        url: \"/msService/WOM/printManage/printDate/generateCode\",\n        isRef: false, // 是否开启参照\n        width: ''350px'',\n        height: ''380px'',\n        buttons: [\n            {\n                text: \"生成\",\n                type: \"primary\",\n                onClick: function (event) {\n                    // 必填校验\n                    let errorMsg = '''';\n                    //生产日期\n                    let manuDate = event.ReactAPI.getComponentAPI(\"DatePicker\").APIs(\"printDate.manuDate\").getValue();\n                    if (manuDate === '''' || manuDate === null) {\n                        errorMsg += ''请选择生产日期！</br>'';\n                    }\n                    //有效期\n                    let approveDate = event.ReactAPI.getComponentAPI(\"DatePicker\").APIs(\"printDate.approveDate\").getValue();\n                    if (approveDate === '''' || approveDate === null) {\n                        errorMsg += ''请选择有效期！</br>'';\n                    }\n                    // 打印机\n                    let print = event.ReactAPI.getComponentAPI(\"Reference\").APIs(\"printDate.printId.aimHost\").getValue();\n                    if (print.length === 0) {\n                        errorMsg += ''请选择打印机！</br>'';\n                    }\n                    // 打印数量\n                    let printCount = event.ReactAPI.getComponentAPI(\"InputNumber\").APIs(\"printDate.printNumber\").getValue();\n                    if (printCount === '''' || printCount === null) {\n                        errorMsg += ''请输入打印数量！</br>'';\n                    } else if (printCount > 10000) {\n                        errorMsg += ''打印数量不能超过1万！</br>'';\n                    }\n                    if (errorMsg.length > 0) {\n                        event.ReactAPI.showMessage(\"w\", errorMsg);\n                        return false;\n                    }\n\n                    event.ReactAPI.openLoading(\"生成中\");\n                    // 组织数据\n                    let data = {\n                        // 工单id\n                        \"taskId\": seleData[0].id,\n                        // 生产日期\n                        \"manuDate\": manuDate,\n                        // 有效期\n                        \"approveDate\": approveDate,\n                        // 打印机id\n                        \"printId\": print[0].id,\n                        // 打印数量\n                        \"printCount\": printCount\n                    }\n                    //异步\n                    ReactAPI.request(\n                        {\n                            type: \"post\",\n                            data: data,\n                            url: \"/msService/WOM/printManage/generateQrCode\"\n                        },\n                        function (res) {\n                            event.ReactAPI.closeLoading();\n                            if (res.code !== 200) {\n                                event.ReactAPI.showMessage(\"w\", res.message);\n                                return false;\n                            }\n                            ReactAPI.showMessage(\"s\", ''生成成功！'');\n                            setTimeout(() => {\n                                ReactAPI.destroyDialog(\"newDialog\");\n                            }, 3000);\n                        }\n                    );\n                }\n            }, {\n                text: \"生成并打印\",\n                type: \"primary\",\n                style: { width: \"100px\" },\n                onClick: function (event) {\n                    // 必填校验\n                    let errorMsg = '''';\n                    //生产日期\n                    let manuDate = event.ReactAPI.getComponentAPI(\"DatePicker\").APIs(\"printDate.manuDate\").getValue();\n                    if (manuDate === '''' || manuDate === null) {\n                        errorMsg += ''请选择生产日期！</br>'';\n                    }\n                    //有效期\n                    let approveDate = event.ReactAPI.getComponentAPI(\"DatePicker\").APIs(\"printDate.approveDate\").getValue();\n                    if (approveDate === '''' || approveDate === null) {\n                        errorMsg += ''请选择有效期！</br>'';\n                    }\n                    // 打印机\n                    let print = event.ReactAPI.getComponentAPI(\"Reference\").APIs(\"printDate.printId.aimHost\").getValue();\n                    if (print.length === 0) {\n                        errorMsg += ''请选择打印机！</br>'';\n                    }\n                    // 打印数量\n                    let printCount = event.ReactAPI.getComponentAPI(\"InputNumber\").APIs(\"printDate.printNumber\").getValue();\n                    if (printCount === '''' || printCount === null) {\n                        errorMsg += ''请输入打印数量！</br>'';\n                    } else if (printCount > 10000) {\n                        errorMsg += ''打印数量不能超过1万！</br>'';\n                    }\n                    if (errorMsg.length > 0) {\n                        event.ReactAPI.showMessage(\"w\", errorMsg);\n                        return false;\n                    }\n\n                    event.ReactAPI.openLoading(\"生成中\");\n                    // 组织数据\n                    let data = {\n                        // 工单id\n                        \"taskId\": seleData[0].id,\n                        // 生产日期\n                        \"manuDate\": manuDate,\n                        // 有效期\n                        \"approveDate\": approveDate,\n                        // 打印机id\n                        \"printId\": print[0].id,\n                        // 打印数量\n                        \"printCount\": printCount\n                    }\n\n                    //异步 生成唯一码\n                    ReactAPI.request(\n                        {\n                            type: \"post\",\n                            data: data,\n                            url: \"/msService/WOM/printManage/generateQrCode\"\n                        },\n                        function (res) {\n                            event.ReactAPI.closeLoading();\n                            \n                            if (res.code !== 200) {\n                                event.ReactAPI.showMessage(\"w\", res.message);\n                                return false;\n                            }\n\n                            event.ReactAPI.openLoading(\"打印中\");\n                            // 组织打印数据 \n                            var printInfoList = res.data;\n\n                            var copyPrintInfoList = [];\n                            for (let index = 0; index < printInfoList.length; index++) {\n                                let msg = ''\"'' + printInfoList[index] + ''\" \"'' + printInfoList[index].split('','')[0] + ''\" \"'' + printInfoList[index].split('','')[3] + ''\"'';\n                                copyPrintInfoList.push(msg);\n                            }\n                            let data = {\n                                \"host\": print[0].aimHost,\n                                \"port\": print[0].port,\n                                \"printInfo\": copyPrintInfoList\n                            }\n                            // 打印\n                            ReactAPI.request(\n                                {\n                                    type: \"post\",\n                                    data: data,\n                                    url: \"/msService/packConfigManag/packMessage/printLog/startPrint\"\n                                },\n                                function (res) {\n                                    if (res.code !== 200) {\n                                        event.ReactAPI.closeLoading();\n                                        event.ReactAPI.showMessage(\"w\", res.message);\n                                        return false;\n                                    }\n                                    // 处理打印结果\n                                    var womPackageQrcodeList = [];\n                                    for (let index = 0; index < copyPrintInfoList.length; index++) {\n                                        let detail = copyPrintInfoList[index];\n                                        let isPrint = 0;\n                                        if (res.data[detail].indexOf(''OK'')!==-1) {\n                                            isPrint = 1;\n                                        }\n                                        let womPackageQrcode = {\n                                            \"isPrint\": isPrint,\n                                            \"detail\": detail.split(''\"'')[1]\n                                        }\n                                        womPackageQrcodeList.push(womPackageQrcode);\n                                    }\n\n                                    //异步 修改成打印结果\n                                    ReactAPI.request(\n                                        {\n                                            type: \"post\",\n                                            data: womPackageQrcodeList,\n                                            url: \"/msService/WOM/printManage/backfill-printInfo\"\n                                        },\n                                        function (res) {\n                                            event.ReactAPI.showMessage(\"s\", ''打印完成！'');\n                                            event.ReactAPI.closeLoading();\n                                            setTimeout(() => {\n                                                ReactAPI.destroyDialog(\"newDialog\");\n                                            }, 3000);\n                                        }\n                                    );\n                                }\n                            );\n                        }\n                    );\n                }\n            }, {\n                text: \"取消\",\n                type: \"cancel\",\n                onClick: function (event) {\n                    ReactAPI.destroyDialog(\"newDialog\");\n                }\n            }\n        ]\n    });\n}","funcbody_es5":"function customClick() {\n    var seleData = ReactAPI.getComponentAPI(\"SupDataGrid\").APIs(''WOM_1.0.0_produceTask_makeTaskList_produceTask_sdg'').getSelecteds();\n    if (seleData.length === 0) {\n        ReactAPI.showMessage(\"w\", ''请选择一条记录进行操作！'');\n        return false;\n    }\n    // let runState = seleData[0].taskRunState;\n    // if (!(runState !== null && (runState.id === ''WOM_runState/runing'' || runState.id === ''WOM_runState/finished''))) {\n    //     ReactAPI.showMessage(\"w\", ''只有执行中和已完成的工单可以生成二维码！'');\n    //     return false;\n    // }\n    // 二维码生成窗口\n    ReactAPI.createDialog(\"newDialog\", {\n        title: \"二维码生成\",\n        url: \"/msService/WOM/printManage/printDate/generateCode\",\n        isRef: false, // 是否开启参照\n        width: ''350px'',\n        height: ''380px'',\n        buttons: [{\n            text: \"生成\",\n            type: \"primary\",\n            onClick: function onClick(event) {\n                // 必填校验\n                var errorMsg = '''';\n                //生产日期\n                var manuDate = event.ReactAPI.getComponentAPI(\"DatePicker\").APIs(\"printDate.manuDate\").getValue();\n                if (manuDate === '''' || manuDate === null) {\n                    errorMsg += ''请选择生产日期！</br>'';\n                }\n                //有效期\n                var approveDate = event.ReactAPI.getComponentAPI(\"DatePicker\").APIs(\"printDate.approveDate\").getValue();\n                if (approveDate === '''' || approveDate === null) {\n                    errorMsg += ''请选择有效期！</br>'';\n                }\n                // 打印机\n                var print = event.ReactAPI.getComponentAPI(\"Reference\").APIs(\"printDate.printId.aimHost\").getValue();\n                if (print.length === 0) {\n                    errorMsg += ''请选择打印机！</br>'';\n                }\n                // 打印数量\n                var printCount = event.ReactAPI.getComponentAPI(\"InputNumber\").APIs(\"printDate.printNumber\").getValue();\n                if (printCount === '''' || printCount === null) {\n                    errorMsg += ''请输入打印数量！</br>'';\n                } else if (printCount > 10000) {\n                    errorMsg += ''打印数量不能超过1万！</br>'';\n                }\n                if (errorMsg.length > 0) {\n                    event.ReactAPI.showMessage(\"w\", errorMsg);\n                    return false;\n                }\n\n                event.ReactAPI.openLoading(\"生成中\");\n                // 组织数据\n                var data = {\n                    // 工单id\n                    \"taskId\": seleData[0].id,\n                    // 生产日期\n                    \"manuDate\": manuDate,\n                    // 有效期\n                    \"approveDate\": approveDate,\n                    // 打印机id\n                    \"printId\": print[0].id,\n                    // 打印数量\n                    \"printCount\": printCount\n                    //异步\n                };ReactAPI.request({\n                    type: \"post\",\n                    data: data,\n                    url: \"/msService/WOM/printManage/generateQrCode\"\n                }, function (res) {\n                    event.ReactAPI.closeLoading();\n                    if (res.code !== 200) {\n                        event.ReactAPI.showMessage(\"w\", res.message);\n                        return false;\n                    }\n                    ReactAPI.showMessage(\"s\", ''生成成功！'');\n                    setTimeout(function () {\n                        ReactAPI.destroyDialog(\"newDialog\");\n                    }, 3000);\n                });\n            }\n        }, {\n            text: \"生成并打印\",\n            type: \"primary\",\n            style: { width: \"100px\" },\n            onClick: function onClick(event) {\n                // 必填校验\n                var errorMsg = '''';\n                //生产日期\n                var manuDate = event.ReactAPI.getComponentAPI(\"DatePicker\").APIs(\"printDate.manuDate\").getValue();\n                if (manuDate === '''' || manuDate === null) {\n                    errorMsg += ''请选择生产日期！</br>'';\n                }\n                //有效期\n                var approveDate = event.ReactAPI.getComponentAPI(\"DatePicker\").APIs(\"printDate.approveDate\").getValue();\n                if (approveDate === '''' || approveDate === null) {\n                    errorMsg += ''请选择有效期！</br>'';\n                }\n                // 打印机\n                var print = event.ReactAPI.getComponentAPI(\"Reference\").APIs(\"printDate.printId.aimHost\").getValue();\n                if (print.length === 0) {\n                    errorMsg += ''请选择打印机！</br>'';\n                }\n                // 打印数量\n                var printCount = event.ReactAPI.getComponentAPI(\"InputNumber\").APIs(\"printDate.printNumber\").getValue();\n                if (printCount === '''' || printCount === null) {\n                    errorMsg += ''请输入打印数量！</br>'';\n                } else if (printCount > 10000) {\n                    errorMsg += ''打印数量不能超过1万！</br>'';\n                }\n                if (errorMsg.length > 0) {\n                    event.ReactAPI.showMessage(\"w\", errorMsg);\n                    return false;\n                }\n\n                event.ReactAPI.openLoading(\"生成中\");\n                // 组织数据\n                var data = {\n                    // 工单id\n                    \"taskId\": seleData[0].id,\n                    // 生产日期\n                    \"manuDate\": manuDate,\n                    // 有效期\n                    \"approveDate\": approveDate,\n                    // 打印机id\n                    \"printId\": print[0].id,\n                    // 打印数量\n                    \"printCount\": printCount\n\n                    //异步 生成唯一码\n                };ReactAPI.request({\n                    type: \"post\",\n                    data: data,\n                    url: \"/msService/WOM/printManage/generateQrCode\"\n                }, function (res) {\n                    event.ReactAPI.closeLoading();\n\n                    if (res.code !== 200) {\n                        event.ReactAPI.showMessage(\"w\", res.message);\n                        return false;\n                    }\n\n                    event.ReactAPI.openLoading(\"打印中\");\n                    // 组织打印数据 \n                    var printInfoList = res.data;\n\n                    var copyPrintInfoList = [];\n                    for (var index = 0; index < printInfoList.length; index++) {\n                        var msg = ''\"'' + printInfoList[index] + ''\" \"'' + printInfoList[index].split('','')[0] + ''\" \"'' + printInfoList[index].split('','')[3] + ''\"'';\n                        copyPrintInfoList.push(msg);\n                    }\n                    var data = {\n                        \"host\": print[0].aimHost,\n                        \"port\": print[0].port,\n                        \"printInfo\": copyPrintInfoList\n                        // 打印\n                    };ReactAPI.request({\n                        type: \"post\",\n                        data: data,\n                        url: \"/msService/packConfigManag/packMessage/printLog/startPrint\"\n                    }, function (res) {\n                        if (res.code !== 200) {\n                            event.ReactAPI.closeLoading();\n                            event.ReactAPI.showMessage(\"w\", res.message);\n                            return false;\n                        }\n                        // 处理打印结果\n                        var womPackageQrcodeList = [];\n                        for (var _index = 0; _index < copyPrintInfoList.length; _index++) {\n                            var detail = copyPrintInfoList[_index];\n                            var isPrint = 0;\n                            if (res.data[detail].indexOf(''OK'') !== -1) {\n                                isPrint = 1;\n                            }\n                            var womPackageQrcode = {\n                                \"isPrint\": isPrint,\n                                \"detail\": detail.split(''\"'')[1]\n                            };\n                            womPackageQrcodeList.push(womPackageQrcode);\n                        }\n\n                        //异步 修改成打印结果\n                        ReactAPI.request({\n                            type: \"post\",\n                            data: womPackageQrcodeList,\n                            url: \"/msService/WOM/printManage/backfill-printInfo\"\n                        }, function (res) {\n                            event.ReactAPI.showMessage(\"s\", ''打印完成！'');\n                            event.ReactAPI.closeLoading();\n                            setTimeout(function () {\n                                ReactAPI.destroyDialog(\"newDialog\");\n                            }, 3000);\n                        });\n                    });\n                });\n            }\n        }, {\n            text: \"取消\",\n            type: \"cancel\",\n            onClick: function onClick(event) {\n                ReactAPI.destroyDialog(\"newDialog\");\n            }\n        }]\n    });\n}","iscallback":"false","iscustomfunc":"false","useInMore":"false","isconfirm":"false","isSignatureConfig":true,"cellCode":"cell_1647831268646_5534","ecEnv":"product","regionType":"BUTTON","i18nKey":"WOM.buttonPropertyshowName.randon1647831278745.flag","name":"生成二维码","operateType":"CUSTOM","onclick":"customClick()","ONCLICK":"customClick()","CODE":"makeTaskList_generateCode_add_WOM_1.0.0_produceTask_makeTaskList","NAME":"生成二维码","ICONCLS":"cui-btn-add","USEINMORE":"false","SEPARATENUM":"0"}],"fields":[{"key":"tableNo","namekey":"ec.common.tableNo","showType":"TEXTFIELD","showFormat":"TEXT","width":160,"isHidden":false,"columnType":"TEXT"},{"key":"productId.code","namekey":"WOM.propertyshowName.randon1575439337444.flag","showType":"TEXTFIELD","showFormat":"TEXT","width":100,"isHidden":false,"columnType":"TEXT"},{"key":"productId.name","namekey":"WOM.propertyshowName.randon1575439344250.flag","showType":"TEXTFIELD","showFormat":"TEXT","width":100,"isHidden":false,"columnType":"TEXT"},{"key":"produceBatchNum","namekey":"WOM.produceTask.ProduceTask.produceBatchNum","showType":"TEXTFIELD","showFormat":"TEXT","width":100,"isHidden":false,"columnType":"BAPCODE"},{"key":"formulaId.formualCode","namekey":"RM.formula.Formula.formualCode","showType":"TEXTFIELD","showFormat":"TEXT","width":100,"isHidden":false,"columnType":"BAPCODE"},{"key":"formulaId.setProcess","namekey":"RM.formula.Formula.setProcess","showType":"SELECTCOMP","showFormat":"SELECTCOMP","width":100,"isHidd